$(document).ready(function(){var a=window.chartLabels||{sales:"Sales",purchases:"Purchases",expenses:"Expenses",payment_sent:"Payment Sent",payment_received:"Payment Received"};let t=document.getElementById("salesPurchasesChart");$.get("/sales-purchases/chart-data",function(e){new Chart(t,{type:"bar",data:{labels:e.sales.original.days,datasets:[{label:a.sales,data:e.sales.original.data,backgroundColor:["#6366F1"],borderColor:["#6366F1"],borderWidth:1},{label:a.purchases,data:e.purchases.original.data,backgroundColor:["#A5B4FC"],borderColor:["#A5B4FC"],borderWidth:1}]},options:{scales:{y:{beginAtZero:!0}}}})});let r=document.getElementById("currentMonthChart");$.get("/current-month/chart-data",function(e){new Chart(r,{type:"doughnut",data:{labels:[a.sales,a.purchases,a.expenses],datasets:[{data:[e.sales,e.purchases,e.expenses],backgroundColor:["#F59E0B","#0284C7","#EF4444"],hoverBackgroundColor:["#F59E0B","#0284C7","#EF4444"]}]}})});let s=document.getElementById("paymentChart");$.get("/payment-flow/chart-data",function(e){new Chart(s,{type:"line",data:{labels:e.months,datasets:[{label:a.payment_sent,data:e.payment_sent,fill:!1,borderColor:"#EA580C",tension:0},{label:a.payment_received,data:e.payment_received,fill:!1,borderColor:"#2563EB",tension:0}]}})})});
